import{_ as o,o as p,c as e,a4 as u}from"./chunks/framework.BSR3y9uA.js";const m=JSON.parse('{"title":"Эмпатия","description":"","frontmatter":{"title":"Эмпатия","date":"2020-09-21T00:00:00.000Z"},"headers":[],"relativePath":"posts/2020-09-21-empathy.md","filePath":"posts/2020-09-21-empathy.md"}'),a={name:"posts/2020-09-21-empathy.md"};function r(i,t,q,l,_,s){return p(),e("div",null,[...t[0]||(t[0]=[u('<p>Эмпатия это осознанное сопереживание другому человеку без потери ощущения источника этого переживания.</p><p>Если источник переживания не осознаётся, это называется слиянием, отождествлением себя с другим. Моих чувств нет, есть только чувства другого человека.</p><p>Эмпатия является важным профессиональным навыком специалистов, работающих с людьми. Развить эмпатию может любой, кроме людей с нарциссическими и психопатическими расстройствами, но им это и не нужно, ибо восприятие другого как субъекта для них просто невозможно.</p><p>Человек, способный к эмпатии, воспринимается как человек, смотрящий &quot;прямо в душу&quot;, &quot;он меня видит&quot;, что иногда воспринимается сначала с опасением неблагоприятной реакции на переживания. Но эмпатичные люди, как правило, понимают и соблюдают границы.</p><p>Эмпатическое слушание, или активное слушание позволяет точно понять эмоциональное состояние собеседника, один мой знакомый психотерапевт шутя утверждает, что он зарабатывает исключительно произнося фразы &quot;Ага&quot;, &quot;Угу&quot;, &quot;Продолжайте&quot;, &quot;Так-так&quot;, &quot;Ммм&quot;, &quot;Хм...&quot; в правильных интонациях, но, увы, это лишь &quot;первая психологическая помощь&quot;, вопреки мифам, этого недостаточно чтобы быть профессиональным психологом.</p><p>Автор развивает эмпатию слушая музыку. Любая музыка это выражение эмоции, песня богата интонациями, которые можно услышать и в речи. Можно закрыть глаза и представить себе театр, где каждая партия - это персонаж со своей индивидуальностью и отношениями с другими. Мелодия как правило построена по тем же принципам, что и пьеса, и любая другая лирика. Пролог, завязка, развитие действия, кульминация, завязка, эпилог. Кульминаций может быть несколько, каждая со своей завязкой, ведущей к следующему моменту наивысшего напряжения.</p><p>Сольфеджио, столь непонятное мне в детстве, в зрелости лет заиграло новыми красками. Все знают что минорный аккорд звучит печально, а мажорный - радостно. Но можно построить последовательность минорных аккордов так, что она зазвучит с надеждой, напряжением, благородством. Кварто-квинтовый круг можно изучать бесконечно.</p><p>Сложности возникают с называнием переживаний, это приходит только с опытом и определенным образованием в этой области. Хорошо помогает изучение <a href="http://urokikino.ru/emotion_theory_1/" target="_blank" rel="noreferrer">цветка эмоций Роберта Плутчика и различных списков эмоций</a></p><p>Самое сложное в общении, обычно, слушать и слышать, а не ждать очереди высказаться.</p><p>Поделюсь с вами одной историей с хорошим таким панчем в конце. Эндрю Скотт, сыгравший Мориарти в сериале BBC &quot;Шерлок&quot; из отвратительного психованного злодея вдруг стал секс-символом всей Великобритании благодаря роли священника в сериале &quot;Дрянь&quot;. Так почему актёр-гей, сыгравший священника-алкоголика с темным прошлым стал &quot;hot priest&quot;?</p><p>В передаче Saturday Night Live автор и главная героиня сериала Уоллер-Бридж призналась, что они с Эндрю долго пытались понять, в чем секрет успеха его героя. Но в итоге разгадка оказалась совсем легкой — он просто умеет слушать.</p><p>Примерно такой же посыл у британского многосерийного фильма Казанова 2005 года.</p><p>Психологи и психотерапевты используют следующие техники активного слушания для поддержания фокуса внимании на клиенте и развития беседы, когда повисла тишина:</p><ul><li>Пауза (прежде чем что-то ответить, сделайте два-три вдоха и выдоха)</li><li>Уточнение (если что-то непонятно, не нужно делать вид что вы поняли, переспросите)</li><li>Парафраз - обобщите сказанное своими словами</li><li>Развитие мысли - скажите какие ассоциации приходят по поводу сказанного</li><li>Сообщение о своих чувствах или возможных чувствах собеседника</li><li>Замечания о контексте беседы, например, &quot;похоже, мы зашли в тупик&quot; или, мой любимый вопрос &quot;как вам кажется, что сейчас происходит?&quot;</li></ul>',14)])])}const c=o(a,[["render",r]]);export{m as __pageData,c as default};
